nfig.class);\n\n        NotificationController controller = \n            context.getBean(NotificationController.class);\n\n        controller.print();  // Hello from Service / Spring IoC\n    }\n}\n\n// Configuration\n\n@Configuration\nclass AppConfig {\n\n    @Bean\n    MessageService messageService() {\n        return new MessageService();\n    }\n\n    @Bean\n    NotificationController notificationController(MessageService messageService) {\n        return new NotificationController(messageService);\n    }\n}\n\n// Beans\n\nclass MessageService {\n    public String getMessage() {\n        return "Hello from Service / Spring IoC";\n    }\n}\n\nclass NotificationController {\n    private final MessageService messageService;\n\n    public NotificationController(MessageService messageService) {\n        this.messageService = messageService;\n    }\n\n    public void print() {\n        System.out.println(messageService.getMessage());\n    }\n}\n~~~	2026-05-26 21:50:21.868849	0.59	2026-06-03 21:53:18.8293	4. Spring IoC	2026-05-27 21:53:18.830381	2	JVM	Spring	Framework	Inversion of Control
23	A class should have only one reason to change.  \n\nThis does not mean that a class must do only one thing.  \nSRP talks about reason to change, not number of methods, not amount of logic.	2026-05-27 22:14:52.371474	0.6499999999999999	2026-06-10 22:19:53.989798	1. Single Responsibility Principle (SRP)	2026-05-27 22:19:53.99077	7	JVM	Java	SOLID	SRP
24	This class has multiple reasons to change:\n\nChange / Reason:  \n\n- Salary rules change (HR / business policy)\n- Report format changes (Reporting / presentation)\n- Persistence changes (Infrastructure / database)\n\nThese reasons come from different actors (HR, finance, DBA, UI team).  \nThat’s the real SRP violation.  \n\n~~~java\n/**\n * SRP - Non complient example\n * ===========================\n * Employee with multiple legitimate beharviors\n */\npackage solid.srp.non_compliant;\n\npublic class BadPayrollApplication {\n    public static void main(String[] args) {\n\n        Employee employee = new Employee("John", 1000);\n        System.out.println(employee.generatePayrollReport());\n        employee.saveToDatabase();\n\n        /*\n            Employee: John, Salary: 1200.0\n            Saving employee to DB\n        */\n    }\n}\n\nclass Employee {\n    private final String name;\n    private final double baseSalary;\n\n    Employee(String name, double baseSalary) {\n        this.name = name;\n        this.baseSalary = baseSalary;\n    }\n\n    double calculateSalary() {\n        return baseSalary * 1.2;\n    }\n\n    String generatePayrollReport() {\n        return "Employee: " + name + ", Salary: " + calculateSalary();\n    }\n\n    void saveToDatabase() {\n        System.out.println("Saving employee to DB");\n       \n    }\n}\n~~~	2026-05-27 22:14:52.3769	0.62	2026-06-10 22:29:15.97874	2. Bad Implementation (violates SRP)	2026-05-27 22:29:15.979945	7	JVM	Java	SOLID	SRP
26	SRP is about actors, not code size.  \nA class should be responsible to only one actor.  \n\nAsk these questions:\n\n- Who will ask for this change?\n- Are these changes requested by different people/teams?\n- Whould these changes happen for different business reasons?\n\nIf the answer is yes, SRP is beaing violeted.	2026-05-27 22:14:52.392267	0.43999999999999995	2026-05-28 22:34:57.082545	4. Key Insights (SRP)	2026-05-27 22:34:57.083298	7	JVM	Java	SOLID	SRP
25	In this example, Employee:\n\n- Has behavior\n- Has multiple methods\n- Still SRP-compliant\n\nBecause:\n\n- All changes to Employee come from one reason:\n  changes in employee-related business rules\n\n~~~java\n/**\n * SRP - Compliant design\n * ======================\n * All changes to Employee come from one reason:\n * changes in employee-related business rules\n */\npackage solid.srp;\n\npublic class PayrollApplication {\n    public static void main(String[] args) {\n\n        Employee employee = new Employee("John", 1000);\n        PayrollReportService service = new PayrollReportService();\n        EmployeeRepository repository = new EmployeeRepository();\n        service.generate(employee);\n        repository.save(employee);\n\n        /*\n            Employee: John / Salary: 1200.0\n            Saving employee to DB: John\n        */\n    }\n}\n\nclass Employee {\n    private final String name;\n    private final double baseSalary;\n\n    Employee(String name, double baseSalary) {\n        this.name = name;\n        this.baseSalary = baseSalary;\n    }\n\n    double calculateSalary() {\n        return baseSalary * 1.2;\n    }\n\n    String getName() {\n        return name;\n    }\n}\n\nclass PayrollReportService {\n    void generate(Employee employee) {\n        System.out.println(\n            "Reports employee: " + employee.getName() + " / " + \n            "Salary: " + employee.calculateSalary()\n        );\n    }\n}\n\nclass EmployeeRepository {\n    void save(Employee employee) {\n        System.out.println("Saving employee to DB: " + employee.getName());\n    }\n}\n~~~	2026-05-27 22:14:52.381669	0.59	2026-06-03 22:32:54.508726	3. SRP-compliant Implementation	2026-05-27 22:32:54.509418	7	JVM	Java	SOLID	SRP
